protected void setName(String name) {
    if (name != null) {
        this.name = name.replace('\\', '/');
    } else {
        this.name = name;
    }
}

additional_testcases.testcase:
@Test
public void backSlashInMiddleOfName() throws Exception {
    ZipArchiveEntry entry = new ZipArchiveEntry("path\\to\\file.txt");
    assertEquals("path/to/file.txt", entry.getName());
}

public void testBackSlashAtStart() throws Exception {
    ZipArchiveEntry entry = new ZipArchiveEntry("\\startfile.txt");
    assertEquals("/startfile.txt", entry.getName());
}

@Test
public void nullNameHandling() throws Exception {
    ZipArchiveEntry entry = new ZipArchiveEntry("");
    entry.setName(null);
    assertNull(entry.getName());
}
